50:     /// Magic number used as a tag, preventing the use of uninitialized pointers.
51:     const beetle: u64 = 0xBEE71E;
52: 
53:     // Since the client interface is an intrusive struct allocated by the user,
54:     // it is exported as an opaque `[_]u64` array.
55:     // An `extern union` is used to ensure a platform-independent size for pointer fields,
56:     // avoiding the need for different versions of `tb_client.h` on 32-bit targets.
57: 
58:     context: extern union {
59:         ptr: ?*anyopaque,
60:         int_ptr: u64,
61:     },
62:     vtable: extern union {
63:         ptr: *const VTable,
64:         int_ptr: u64,
65:     },
66:     locker: Locker,
67:     reserved: u32,
68:     magic_number: u64,
69: 
70:     pub fn init(interface: *ClientInterface, context: *anyopaque, vtable: *const VTable) void {
71:         interface.* = .{
72:             .context = .{ .ptr = context },
73:             .vtable = .{ .ptr = vtable },
74:             .locker = .{},
75:             .reserved = 0,
76:             .magic_number = 0,
77:         };
78:     }
79: 
80:     pub fn submit(interface: *ClientInterface, packet: *Packet.Extern) Error!void {
81:         if (interface.magic_number != beetle) return Error.ClientInvalid;
82:         assert(interface.reserved == 0);
83: 
84:         interface.locker.lock();
85:         defer interface.locker.unlock();
86: 
87:         const context = interface.context.ptr orelse return Error.ClientInvalid;
88:         interface.vtable.ptr.submit_fn(context, packet);
89:     }
90: 
91:     pub fn completion_context(interface: *ClientInterface) Error!usize {
92:         if (interface.magic_number != beetle) return Error.ClientInvalid;
93:         assert(interface.reserved == 0);
94: 
95:         interface.locker.lock();
96:         defer interface.locker.unlock();
97: 
98:         const context = interface.context.ptr orelse return Error.ClientInvalid;
99:         return interface.vtable.ptr.completion_context_fn(context);
100:     }
101: 
102:     pub fn deinit(interface: *ClientInterface) Error!void {
103:         if (interface.magic_number != beetle) return Error.ClientInvalid;
104:         assert(interface.reserved == 0);
105: 
106:         const context: *anyopaque = context: {
107:             interface.locker.lock();
108:             defer interface.locker.unlock();
109: 
110:             const context = interface.context.ptr orelse return Error.ClientInvalid;
111:             interface.context = .{ .ptr = null };
112: 
113:             break :context context;
114:         };
115:         interface.vtable.ptr.deinit_fn(context);
116:     }
117: 
118:     pub fn init_parameters(
119:         interface: *ClientInterface,
120:         out_parameters: *InitParameters,
121:     ) Error!void {
122:         if (interface.magic_number != beetle) return Error.ClientInvalid;
123:         assert(interface.reserved == 0);
124: 
125:         interface.locker.lock();
126:         defer interface.locker.unlock();
127: 
128:         const context = interface.context.ptr orelse return Error.ClientInvalid;
129:         return interface.vtable.ptr.init_parameters_fn(context, out_parameters);
130:     }
131: 
132:     comptime {
133:         assert(@sizeOf(ClientInterface) == 32);
134:         assert(@alignOf(ClientInterface) == 8);
135:     }
136: };
137: 
138: /// The function pointer called by the IO thread when a request is completed or fails.
139: /// The memory referenced by `result` is only valid for the duration of this callback.
140: /// `result_ptr` is `null` for unsuccessful requests. See `packet.status` for more details.
141: pub const CompletionCallback = *const fn (
142:     context: usize,
143:     packet: *Packet.Extern,
144:     timestamp: u64,
145:     result: ?[*]const u8,
146:     result_size: u32,
147: ) callconv(.c) void;
148: 
149: pub const InitError = std.mem.Allocator.Error || error{
150:     Unexpected,
151:     AddressInvalid,
152:     AddressLimitExceeded,
153:     SystemResources,
154:     NetworkSubsystemFailed,
155: };
156: 
157: /// Implements a `ClientInterface` with specialized `vsr.Client` and `StateMachine` types.
158: pub fn ContextType(
159:     comptime Client: type,
160: ) type {
161:     return struct {
162:         const Context = @This();
163:         const GPA = std.heap.GeneralPurposeAllocator(.{
164:             .thread_safe = true,
165:         });
166: 
167:         const Operation = Client.Operation;
168:         const allowed_operations = [_]Operation{
169:             .create_accounts,
170:             .create_transfers,
171:             .lookup_accounts,
172:             .lookup_transfers,
173:             .get_account_transfers,
174:             .get_account_balances,
175:             .query_accounts,
176:             .query_transfers,
177:             .get_change_events,
178:         };
179: 
180:         const UserData = extern struct {
181:             self: *Context,
182:             packet: *Packet,
183: 
184:             comptime {
185:                 assert(@sizeOf(UserData) == @sizeOf(u128));
186:             }
187:         };
188: 
189:         const PacketError = error{
190:             TooMuchData,
191:             ClientShutdown,
192:             ClientEvicted,
193:             ClientReleaseTooLow,
194:             ClientReleaseTooHigh,
195:             InvalidOperation,
196:             InvalidDataSize,
197:         };
198: 
199:         /// Thread-local variable to track whether the current thread is
200:         /// the IO thread or a user thread.
201:         /// Used to assert that certain functions are only called from the
202:         /// correct thread.
203:         threadlocal var thread_caller: union(enum) {
204:             user,
205:             io: std.Thread.Id,
206:         } = .user;
207: 
208:         gpa: GPA,
209:         time_os: TimeOS = .{},
210:         client_id: u128,
211:         cluster_id: u128,
212:         addresses_owned: []const u8,
213: 
214:         addresses: stdx.BoundedArrayType(std.net.Address, constants.replicas_max) = .{},
215:         io: IO,
216:         message_pool: MessagePool,
217:         client: Client,
218:         batch_size_limit: ?u32 = null,
219: 
220:         completion_callback: CompletionCallback,
221:         completion_context: usize,
222: 
223:         interface: *ClientInterface,
224:         submitted: Packet.Queue,
225:         pending: Packet.Queue,
226: 
227:         signal: Signal,
228:         eviction_reason: ?vsr.Header.Eviction.Reason = null,
229:         thread: std.Thread,
230: 
231:         previous_request_instant: stdx.Instant,
232:         previous_request_latency: ?stdx.Duration = null,
233: 
234:         pub fn init(
235:             root_allocator: std.mem.Allocator,
236:             client_out: *ClientInterface,
237:             cluster_id: u128,
238:             addresses: []const u8,
239:             completion_ctx: usize,
240:             completion_callback: CompletionCallback,
241:         ) InitError!void {
242:             var context: *Context = context: {
243:                 // Wrap the root allocator - usually heap.c_allocator when built as a library - in
244:                 // a GPA to keep maximum compatibility while gaining the extra safety. As a library,
245:                 // libtbclient is running inside another process's address space.
246:                 var gpa = GPA{
247:                     .backing_allocator = root_allocator,
248:                 };
249:                 errdefer assert(gpa.deinit() == .ok);
250: 
251:                 const context = try gpa.allocator().create(Context);
252: 
253:                 // Moving the GPA is safe, since we don't have any live reference to `allocator`.
254:                 context.gpa = gpa;
255: 
256:                 break :context context;
257:             };
258: 
259:             errdefer {
260:                 var gpa: GPA = context.gpa;
261:                 gpa.allocator().destroy(context);
262:                 assert(gpa.deinit() == .ok);
263:             }
264: 
265:             const allocator = context.gpa.allocator();
266: 
267:             context.* = .{
268:                 .gpa = context.gpa,
269: 
270:                 .client_id = stdx.unique_u128(),
271:                 .cluster_id = cluster_id,
272: 
273:                 .completion_callback = completion_callback,
274:                 .completion_context = completion_ctx,
275: 
276:                 .interface = client_out,
277:                 .submitted = Packet.Queue.init(.{
278:                     .name = null,
279:                     .verify_push = builtin.is_test,
280:                 }),
281:                 .pending = Packet.Queue.init(.{
282:                     .name = null,
283:                     .verify_push = builtin.is_test,
284:                 }),
285: 
286:                 .addresses_owned = undefined,
287:                 .io = undefined,
288:                 .message_pool = undefined,
289:                 .client = undefined,
290:                 .signal = undefined,
291:                 .thread = undefined,
292:                 .previous_request_instant = undefined,
293:             };
294:             context.addresses_owned = try allocator.dupe(u8, addresses);
295:             errdefer allocator.free(context.addresses_owned);
296: 
297:             const time = context.time_os.time();
298: 
299:             log.debug("{}: init: parsing vsr addresses: {s}", .{ context.client_id, addresses });
300:             context.addresses = .{};
301:             const addresses_parsed = vsr.parse_addresses(
302:                 addresses,
303:                 context.addresses.unused_capacity_slice(),
304:             ) catch |err| return switch (err) {
305:                 error.AddressLimitExceeded => error.AddressLimitExceeded,
306:                 error.AddressHasMoreThanOneColon,
307:                 error.AddressHasTrailingComma,
308:                 error.AddressInvalid,
309:                 error.PortInvalid,
310:                 error.PortOverflow,
311:                 => error.AddressInvalid,
312:             };
313:             assert(addresses_parsed.len > 0);
314:             assert(addresses_parsed.len <= constants.replicas_max);
315:             context.addresses.resize(addresses_parsed.len) catch unreachable;
316: 
317:             log.debug("{}: init: initializing IO", .{context.client_id});
318:             context.io = IO.init(32, 0) catch |err| {
319:                 log.err("{}: failed to initialize IO: {s}", .{
320:                     context.client_id,
321:                     @errorName(err),
322:                 });
323:                 return switch (err) {
324:                     error.ProcessFdQuotaExceeded => error.SystemResources,
325:                     error.Unexpected => error.Unexpected,
326:                     else => unreachable,
327:                 };
328:             };
329:             errdefer context.io.deinit();
330: 
331:             log.debug("{}: init: initializing MessagePool", .{context.client_id});
332:             context.message_pool = try MessagePool.init(allocator, .client);
333:             errdefer context.message_pool.deinit(allocator);
334: 
335:             log.debug("{}: init: initializing client (cluster_id={x:0>32}, addresses={any})", .{
336:                 context.client_id,
337:                 cluster_id,
338:                 context.addresses.const_slice(),
339:             });
340:             context.client = Client.init(
341:                 allocator,
342:                 time,
343:                 &context.message_pool,
344:                 .{
345:                     .id = context.client_id,
346:                     .cluster = cluster_id,
347:                     .replica_count = context.addresses.count_as(u8),
348:                     .aof_recovery = false,
349:                     .message_bus_options = .{
350:                         .configuration = context.addresses.const_slice(),
351:                         .io = &context.io,
352:                         .trace = null,
353:                     },
354:                     .eviction_callback = client_eviction_callback,
355:                 },
356:             ) catch |err| {
357:                 log.err("{}: failed to initialize Client: {s}", .{
358:                     context.client_id,
359:                     @errorName(err),
360:                 });
361:                 return switch (err) {
362:                     error.OutOfMemory => error.OutOfMemory,
363:                 };
364:             };
365:             errdefer context.client.deinit(allocator);
366: 
367:             ClientInterface.init(client_out, context, comptime &.{
368:                 .submit_fn = &vtable_submit_fn,
369:                 .completion_context_fn = &vtable_completion_context_fn,
370:                 .deinit_fn = &vtable_deinit_fn,
371:                 .init_parameters_fn = &vtable_init_parameters_fn,
372:             });
373: 
374:             log.debug("{}: init: initializing signal", .{context.client_id});
375:             try context.signal.init(&context.io, Context.signal_notify_callback);
376:             errdefer context.signal.deinit();
377: 
378:             context.previous_request_instant = context.client.time.monotonic();
379:             context.client.register(client_register_callback, @intFromPtr(context));
380: 
381:             log.debug("{}: init: spawning thread", .{context.client_id});
382:             context.thread = std.Thread.spawn(
383:                 .{ .stack_size = io_thread_stack_size },
384:                 Context.io_thread,
385:                 .{context},
386:             ) catch |err| {
387:                 log.err("{}: failed to spawn thread: {s}", .{
388:                     context.client_id,
389:                     @errorName(err),
390:                 });
391:                 return switch (err) {
392:                     error.Unexpected => error.Unexpected,
393:                     error.OutOfMemory => error.OutOfMemory,
394:                     error.SystemResources,
395:                     error.ThreadQuotaExceeded,
396:                     error.LockedMemoryLimitExceeded,
397:                     => error.SystemResources,
398:                 };
399:             };
400: 
401:             // Setting `magic_number` tags the interface as initialized.
402:             // Writing it at the end so that if `init` fails part-way through and the
403:             // user doesn’t handle the error before using it, we'll still be able to validate.
404:             client_out.magic_number = ClientInterface.beetle;
405:         }
406: 
407:         fn deinit(self: *Context) void {
408:             assert(thread_caller == .io);
409:             assert(self.signal.status() == .shutdown_completed);
410:             assert(self.submitted.pop() == null);
411:             assert(self.pending.pop() == null);
412:             maybe(self.eviction_reason != null);
413: 
414:             self.io.cancel_all();
415:             self.signal.deinit();
416:             self.client.deinit(self.gpa.allocator());
417:             self.message_pool.deinit(self.gpa.allocator());
418:             self.io.deinit();
419: 
420:             self.gpa.allocator().free(self.addresses_owned);
421: 
422:             // NB: Copy the allocator back out before trying to destroy `self` with it!
423:             var gpa: GPA = self.gpa;
424:             gpa.allocator().destroy(self);
425:             assert(gpa.deinit() == .ok);
426:         }
427: 
428:         fn tick(self: *Context) void {
429:             if (self.eviction_reason == null) {
430:                 self.client.tick();
431:             }
432:         }
433: 
434:         fn io_thread(self: *Context) void {
435:             // Initializing the flag as the IO thread.
436:             assert(thread_caller == .user);
437:             thread_caller = .{ .io = std.Thread.getCurrentId() };
438:             defer thread_caller = .user;
439: 
440:             while (self.signal.status() != .shutdown_completed) {
441:                 self.tick();
442:                 self.io.run_for_ns(constants.tick_ms * std.time.ns_per_ms) catch |err| {
443:                     log.err("{}: IO.run() failed: {s}", .{
444:                         self.client_id,
445:                         @errorName(err),
446:                     });
447:                     @panic("IO.run() failed");
448:                 };
449:             }
450: 
451:             self.cancel_request_inflight();
452: 
453:             while (self.pending.pop()) |packet| {
454:                 packet.assert_phase(.pending);
455:                 self.packet_cancel(packet);
456:             }
457: 
458:             // The submitted queue is no longer accessible to user threads,
459:             // so synchronization is not required here.
460:             while (self.submitted.pop()) |packet| {
461:                 packet.assert_phase(.submitted);
462:                 self.packet_cancel(packet);
463:             }
464: 
465:             self.deinit();
466:         }
467: 
468:         /// Cancel the current inflight request (and the entire batched linked list of packets),
469:         /// as it won't be replied anymore.
470:         fn cancel_request_inflight(self: *Context) void {
471:             assert(thread_caller == .io);
472:             if (self.client.request_inflight) |*inflight| {
473:                 if (inflight.message.header.operation != .register) {
474:                     const packet: *Packet = @as(UserData, @bitCast(inflight.user_data)).packet;
475:                     packet.assert_phase(.sent);
476:                     self.packet_cancel(packet);
477:                 }
478:             }
479:         }
480: 
481:         /// Calls the user callback when a packet (the entire batched linked list of packets)
482:         /// is canceled due to the client being either evicted or shutdown.
483:         fn packet_cancel(self: *Context, packet_list: *Packet) void {
484:             assert(thread_caller == .io);
485:             assert(packet_list.link.next == null);
486:             assert(packet_list.phase != .complete);
487:             packet_list.assert_phase(packet_list.phase);
488: 
489:             const result = if (self.eviction_reason) |reason| switch (reason) {
490:                 .reserved => unreachable,
491:                 .client_release_too_low => error.ClientReleaseTooLow,
492:                 .client_release_too_high => error.ClientReleaseTooHigh,
493:                 else => error.ClientEvicted,
494:             } else result: {
495:                 assert(self.signal.status() != .running);
496:                 break :result error.ClientShutdown;
497:             };
498: 
499:             var it: ?*Packet = packet_list;
500:             while (it) |batched| {
501:                 if (batched != packet_list) batched.assert_phase(.batched);
502:                 it = batched.multi_batch_next;
503:                 self.notify_completion(batched, result);
504:             }
505:         }
506: 
507:         fn packet_enqueue(self: *Context, packet: *Packet) void {
508:             assert(thread_caller == .io);
509:             assert(self.batch_size_limit != null);
510:             packet.assert_phase(.submitted);
511: 
512:             const operation: Operation = operation_from_int(packet.operation) orelse {
513:                 return self.notify_completion(packet, error.InvalidOperation);
514:             };
515: 
516:             // Make sure the packet.data wouldn't overflow a request,
517:             // and that the corresponding results won't overflow a reply.
518:             const batch: struct {
519:                 event_size: u32,
520:                 result_size: u32,
521:                 event_count: u32,
522:                 result_count_expected: u32,
523:             } = batch: {
524:                 const event_size: u32 = operation.event_size();
525:                 assert(event_size > 0);
526: 
527:                 const result_size: u32 = operation.result_size();
528:                 assert(result_size > 0);
529: 
530:                 const slice: []const u8 = packet.slice();
531:                 assert(slice.len == packet.data_size);
532:                 maybe(slice.len == 0);
533:                 if (slice.len % event_size != 0) {
534:                     return self.notify_completion(packet, error.InvalidDataSize);
535:                 }
536: 
537:                 const event_count: u32 = @intCast(@divExact(slice.len, event_size));
538:                 const event_max: u32 = operation.event_max(self.batch_size_limit.?);
539:                 if (event_count > event_max) {
540:                     return self.notify_completion(packet, error.TooMuchData);
541:                 }
542:                 const result_max: u32 = operation.result_max(self.batch_size_limit.?);
543:                 const result_count_expected: u32 = operation.result_count_expected(slice);
544:                 if (result_count_expected > result_max) {
545:                     return self.notify_completion(packet, error.TooMuchData);
546:                 }
547: 
548:                 break :batch .{
549:                     .event_size = event_size,
550:                     .result_size = result_size,
551:                     .event_count = @intCast(@divExact(slice.len, event_size)),
552:                     .result_count_expected = result_count_expected,
553:                 };
554:             };
555:             assert(packet.data_size == batch.event_count * batch.event_size);
556:             maybe(batch.event_count == 0);
557:             maybe(batch.result_count_expected == 0);
558: 
559:             // Avoid making a packet inflight by cancelling it if the client was shutdown.
560:             if (self.signal.status() != .running) {
561:                 maybe(self.eviction_reason != null);
562:                 self.packet_cancel(packet);
563:                 return;
564:             }
565: 
566:             // Nothing inflight means the packet should be submitted right now.
567:             if (self.client.request_inflight == null) {
568:                 assert(self.pending.count() == 0);
569:                 packet.phase = .pending;
570:                 packet.multi_batch_time_monotonic = self.client.time.monotonic().ns;
571:                 packet.multi_batch_count = 1;
572:                 packet.multi_batch_event_count = @intCast(batch.event_count);
573:                 packet.multi_batch_result_count_expected = @intCast(batch.result_count_expected);
574:                 self.packet_send(packet);
575:                 return;
576:             }
577: 
578:             var it = self.pending.iterate();
579:             while (it.next()) |root| {
580:                 root.assert_phase(.pending);
581: 
582:                 if (root.operation != packet.operation) continue;
583: 
584:                 // Check if the message has enough space for the submitted number of events:
585:                 const request_size: u32 = size: {
586:                     const trailer_size = vsr.multi_batch.trailer_total_size(.{
587:                         .element_size = batch.event_size,
588:                         .batch_count = root.multi_batch_count + 1,
589:                     });
590:                     const event_count: u32 = batch.event_count +
591:                         root.multi_batch_event_count;
592:                     break :size (event_count * batch.event_size) + trailer_size;
593:                 };
594:                 if (request_size > self.batch_size_limit.?) continue;
595: 
596:                 // Check if the reply has enough space for the maximum expected number of results:
597:                 const reply_size_expected: u32 = size: {
598:                     const trailer_size = vsr.multi_batch.trailer_total_size(.{
599:                         .element_size = batch.result_size,
600:                         .batch_count = root.multi_batch_count + 1,
601:                     });
602:                     const event_count: u32 = batch.result_count_expected +
603:                         root.multi_batch_result_count_expected;
604:                     break :size (event_count * batch.result_size) + trailer_size;
605:                 };
606:                 if (reply_size_expected > constants.message_body_size_max) continue;
607: 
608:                 packet.phase = .batched;
609:                 if (root.multi_batch_next == null) {
610:                     assert(root.multi_batch_tail == null);
611:                     assert(root.multi_batch_count == 1);
612:                     root.multi_batch_next = packet;
613:                     root.multi_batch_tail = packet;
614:                 } else {
615:                     assert(root.multi_batch_tail != null);
616:                     assert(root.multi_batch_count > 1);
617:                     root.multi_batch_tail.?.multi_batch_next = packet;
618:                     root.multi_batch_tail = packet;
619:                 }
620:                 root.multi_batch_count += 1;
621:                 root.multi_batch_event_count += @intCast(batch.event_count);
622:                 root.multi_batch_result_count_expected += @intCast(batch.result_count_expected);
623:                 return;
624:             }
625: 
626:             // Couldn't batch with existing packet so push to pending directly.
627:             packet.phase = .pending;
628:             packet.multi_batch_time_monotonic = self.client.time.monotonic().ns;
629:             packet.multi_batch_count = 1;
630:             packet.multi_batch_event_count = @intCast(batch.event_count);
631:             packet.multi_batch_result_count_expected = @intCast(batch.result_count_expected);
632:             self.pending.push(packet);
633:         }
634: 
635:         /// Sends the packet (the entire batched linked list of packets) through the vsr client.
636:         /// Always called by the io thread.
637:         fn packet_send(self: *Context, packet_list: *Packet) void {
638:             assert(thread_caller == .io);
639:             assert(self.batch_size_limit != null);
640:             assert(self.client.request_inflight == null);
641:             packet_list.assert_phase(.pending);
642: 
643:             // On shutdown, cancel this packet as well as any others batched onto it.
644:             if (self.signal.status() != .running) {
645:                 return self.packet_cancel(packet_list);
646:             }
647:             assert(self.eviction_reason == null);
648: 
649:             const message = self.client.get_message().build(.request);
650:             defer {
651:                 self.client.release_message(message.base());
652:                 packet_list.assert_phase(.sent);
653:             }
654: 
655:             const operation: Operation = operation_from_int(packet_list.operation).?;
656:             const event_size: u32 = operation.event_size();
657:             const request_size: u32 = request_size: {
658:                 if (!operation.is_multi_batch()) {
659:                     assert(packet_list.multi_batch_next == null);
660:                     const source: []const u8 = packet_list.slice();
661:                     stdx.copy_disjoint(
662:                         .inexact,
663:                         u8,
664:                         message.buffer[@sizeOf(Header)..],
665:                         source,
666:                     );
667:                     break :request_size @intCast(source.len);
668:                 }
669:                 assert(operation.is_multi_batch());
670: 
671:                 var message_encoder = MultiBatchEncoder.init(message.buffer[@sizeOf(Header)..], .{
672:                     .element_size = event_size,
673:                 });
674: 
675:                 var it: ?*Packet = packet_list;
676:                 var multi_batch_events_count: u16 = 0;
677:                 while (it) |batched| {
678:                     if (batched != packet_list) batched.assert_phase(.batched);
679:                     it = batched.multi_batch_next;
680: 
681:                     const source: []const u8 = batched.slice();
682:                     const target = message_encoder.writable().?;
683:                     assert(target.len >= source.len);
684:                     stdx.copy_disjoint(
685:                         .exact,
686:                         u8,
687:                         target[0..source.len],
688:                         source,
689:                     );
690:                     message_encoder.add(@intCast(source.len));
691: 
692:                     const events_count: u16 = @intCast(@divExact(source.len, event_size));
693:                     multi_batch_events_count += events_count;
694:                 }
695:                 assert(multi_batch_events_count == packet_list.multi_batch_event_count);
696:                 assert(message_encoder.batch_count == packet_list.multi_batch_count);
697: 
698:                 // Check if the reply has enough space for the maximum expected number of results.
699:                 const result_size: u32 = operation.result_size();
700:                 const trailer_size = vsr.multi_batch.trailer_total_size(.{
701:                     .element_size = result_size,
702:                     .batch_count = packet_list.multi_batch_count,
703:                 });
704:                 const reply_size_max: u32 = (result_size *
705:                     packet_list.multi_batch_result_count_expected) + trailer_size;
706:                 assert(reply_size_max % result_size == 0);
707:                 assert(reply_size_max <= constants.message_body_size_max);
708: 
709:                 break :request_size message_encoder.finish();
710:             };
711:             assert(request_size % event_size == 0);
712:             assert(request_size <= self.batch_size_limit.?);
713: 
714:             // Sending the request.
715:             const previous_request_latency =
716:                 self.previous_request_latency orelse stdx.Duration{ .ns = 0 };
717:             message.header.* = .{
718:                 .release = self.client.release,
719:                 .client = self.client.id,
720:                 .request = 0, // Set by client.raw_request.
721:                 .cluster = self.client.cluster,
722:                 .command = .request,
723:                 .operation = operation.to_vsr(),
724:                 .size = @sizeOf(vsr.Header) + request_size,
725:                 .previous_request_latency = @intCast(@min(
726:                     previous_request_latency.to_us(),
727:                     std.math.maxInt(u32),
728:                 )),
729:             };
730: 
731:             self.previous_request_instant = .{ .ns = packet_list.multi_batch_time_monotonic };
732: 
733:             packet_list.phase = .sent;
734:             self.client.raw_request(
735:                 Context.client_result_callback,
736:                 @bitCast(UserData{
737:                     .self = self,
738:                     .packet = packet_list,
739:                 }),
740:                 message.ref(),
741:             );
742:             assert(message.header.request != 0);
743:         }
744: 
745:         fn signal_notify_callback(signal: *Signal) void {
746:             assert(thread_caller == .io);
747: 
748:             const self: *Context = @alignCast(@fieldParentPtr("signal", signal));
749:             switch (self.signal.status()) {
750:                 .running => if (self.batch_size_limit == null) {
751:                     // Don't send any requests until registration completes.
752:                     assert(self.client.request_inflight != null);
753:                     assert(self.client.request_inflight.?.message.header.operation == .register);
754:                     return;
755:                 },
756:                 // Shutdown flushes pending requests.
757:                 .shutdown_completed, .shutdown_requested => return,
758:             }
759: 
760:             // Prevents IO thread starvation under heavy client load.
761:             // Process only the minimal number of packets for the next pending request.
762:             const enqueued_count = self.pending.count();
763:             const safety_limit = 8 * 1024; // Avoid unbounded loop in case of invalid packets.
764:             for (0..safety_limit) |_| {
765:                 const packet: *Packet = pop: {
766:                     self.interface.locker.lock();
767:                     defer self.interface.locker.unlock();
768: 
769:                     break :pop self.submitted.pop() orelse return;
770:                 };
771:                 self.packet_enqueue(packet);
772: 
773:                 // Packets can be processed without increasing `pending.count`:
774:                 // - If the packet is invalid.
775:                 // - If there's no in-flight request, the packet is sent immediately without
776:                 //   using the pending queue.
777:                 // - If the packet can be batched with another previously enqueued packet.
778:                 if (self.pending.count() > enqueued_count) break;
779:             }
780: 
781:             // Defer this work to later,
782:             // allowing the IO thread to remain free for processing completions.
783:             const empty: bool = empty: {
784:                 self.interface.locker.lock();
785:                 defer self.interface.locker.unlock();
786: 
787:                 break :empty self.submitted.empty();
788:             };
789:             if (!empty) {
790:                 self.signal.notify();
791:             }
792:         }
793: 
794:         fn client_register_callback(user_data: u128, result: *const vsr.RegisterResult) void {
795:             assert(thread_caller == .io);
796: 
797:             const self: *Context = @ptrFromInt(@as(usize, @intCast(user_data)));
798:             assert(self.client.request_inflight == null);
799:             assert(self.batch_size_limit == null);
800:             assert(result.batch_size_limit > 0);
801: 
802:             const current_timestamp = self.client.time.monotonic();
803:             self.previous_request_latency =
804:                 current_timestamp.duration_since(self.previous_request_instant);
805: 
806:             // The client might have a smaller message size limit.
807:             maybe(constants.message_body_size_max < result.batch_size_limit);
808:             self.batch_size_limit = @min(result.batch_size_limit, constants.message_body_size_max);
809: 
810:             // Some requests may have queued up while the client was registering.
811:             signal_notify_callback(&self.signal);
812:         }
813: 
814:         fn client_eviction_callback(client: *Client, eviction: *const Message.Eviction) void {
815:             assert(thread_caller == .io);
816: 
817:             const self: *Context = @fieldParentPtr("client", client);
818:             assert(self.eviction_reason == null);
819: 
820:             log.debug("{}: client_eviction_callback: reason={?s} reason_int={}", .{
821:                 self.client_id,
822:                 std.enums.tagName(vsr.Header.Eviction.Reason, eviction.header.reason),
823:                 @intFromEnum(eviction.header.reason),
824:             });
825: 
826:             // The client was evicted, clearing the interface context so no more
827:             // requests can be submitted.
828:             // In-flight requests fail with the eviction reason; subsequent ones fail
829:             // with "shutdown".
830:             self.interface.locker.lock();
831:             defer self.interface.locker.unlock();
832: 
833:             self.interface.context = .{ .ptr = null };
834: 
835:             // Stops the IO thread, which then deinitializes the client before
836:             // it exits (see `io_thread`).
837:             self.eviction_reason = eviction.header.reason;
838:             self.signal.stop();
839:         }
