1036: /// Implements the `Mutex` API as an `extern` struct, based on `std.Thread.Futex`.
1037: /// Vendored from `std.Thread.Mutex.FutexImpl`.
1038: const Locker = extern struct {
1039:     const Futex = std.Thread.Futex;
1040:     const unlocked: u32 = 0b00;
1041:     const locked: u32 = 0b01;
1042:     const contended: u32 = 0b11; // Must contain the `locked` bit for x86 optimization below.
1043: 
1044:     state: std.atomic.Value(u32) = std.atomic.Value(u32).init(unlocked),
1045: 
1046:     fn lock(self: *Locker) void {
1047:         if (!self.try_lock()) {
1048:             self.lock_slow();
1049:         }
1050:     }
1051: 
1052:     fn try_lock(self: *Locker) bool {
1053:         // On x86, use `lock bts` instead of `lock cmpxchg` as:
1054:         // - they both seem to mark the cache-line as modified regardless: https://stackoverflow.com/a/63350048.
1055:         // - `lock bts` is smaller instruction-wise which makes it better for inlining.
1056:         if (comptime builtin.target.cpu.arch.isX86()) {
1057:             const locked_bit = @ctz(locked);
1058:             return self.state.bitSet(locked_bit, .acquire) == 0;
1059:         }
1060: 
1061:         // Acquire barrier ensures grabbing the lock happens before the critical section
1062:         // and that the previous lock holder's critical section happens before we grab the lock.
1063:         return self.state.cmpxchgWeak(unlocked, locked, .acquire, .monotonic) == null;
1064:     }
1065: 
1066:     fn lock_slow(self: *Locker) void {
1067:         @branchHint(.cold);
1068: 
1069:         // Avoid doing an atomic swap below if we already know the state is contended.
1070:         // An atomic swap unconditionally stores which marks the cache-line as modified
1071:         // unnecessarily.
1072:         if (self.state.load(.monotonic) == contended) {
1073:             Futex.wait(&self.state, contended);
1074:         }
1075: 
1076:         // Try to acquire the lock while also telling the existing lock holder that there are
1077:         // threads waiting.
1078:         //
1079:         // Once we sleep on the Futex, we must acquire the mutex using `contended` rather than
1080:         // `locked`.
1081:         // If not, threads sleeping on the Futex wouldn't see the state change in unlock and
1082:         // potentially deadlock.
1083:         // The downside is that the last mutex unlocker will see `contended` and do an unnecessary
1084:         // Futex wake but this is better than having to wake all waiting threads on mutex unlock.
1085:         //
1086:         // Acquire barrier ensures grabbing the lock happens before the critical section
1087:         // and that the previous lock holder's critical section happens before we grab the lock.
1088:         while (self.state.swap(contended, .acquire) != unlocked) {
1089:             Futex.wait(&self.state, contended);
1090:         }
1091:     }
1092: 
1093:     fn unlock(self: *Locker) void {
1094:         // Unlock the mutex and wake up a waiting thread if any.
1095:         //
1096:         // A waiting thread will acquire with `contended` instead of `locked`
1097:         // which ensures that it wakes up another thread on the next unlock().
1098:         //
1099:         // Release barrier ensures the critical section happens before we let go of the lock
1100:         // and that our critical section happens before the next lock holder grabs the lock.
1101:         const state = self.state.swap(unlocked, .release);
1102:         assert(state != unlocked);
1103: 
1104:         if (state == contended) {
1105:             Futex.wake(&self.state, 1);
1106:         }
1107:     }
1108: };
1109: 
