1123: test "Locker: contended" {
1124:     const threads_count = 4;
1125:     const increments = 1000;
1126: 
1127:     const State = struct {
1128:         locker: Locker = .{},
1129:         counter: u32 = 0,
1130:     };
1131: 
1132:     const Runner = struct {
1133:         thread: std.Thread = undefined,
1134:         state: *State,
1135:         fn run(self: *@This()) void {
1136:             while (true) {
1137:                 self.state.locker.lock();
1138:                 defer self.state.locker.unlock();
1139: 
1140:                 if (self.state.counter == increments) break;
1141:                 self.state.counter += 1;
1142:             }
1143:         }
