254:         // Protect everything with a mutex - logging can be called from different threads
255:         // simultaneously, and there's only one buffer for now.
256:         Logging.global.mutex.lock();
257:         defer Logging.global.mutex.unlock();
258: 
259:         const callback = Logging.global.callback orelse return;
260: 
261:         const tb_message_level: tb_log_level = @enumFromInt(@intFromEnum(message_level));
262:         const prefix = if (scope == .default) ": " else "(" ++ @tagName(scope) ++ "): ";
