266:             args,
267:         ) catch |err| switch (err) {
268:             error.NoSpaceLeft => blk: {
269:                 // Print an error indicating the log message has been truncated, before the
270:                 // truncated log itself.
271:                 const message = "the following log message has been truncated:";
272:                 callback(tb_message_level, message.ptr, message.len);
273: 
274:                 break :blk &Logging.global.buffer;
275:             },
276:             else => unreachable,
277:         };
278: 
279:         callback(tb_message_level, output.ptr, @intCast(output.len));
280:     }
